name = "Harry"

print(name[0:3]) # This line prints the value of the variable 'name', which is "Harry".
print(name[-4: -1]) # This line prints the characters from index -4 to index -2 of the string 'name'. Since index -4 corresponds to the character 'a' and index -1 corresponds to the character 'y', the output will be "arr".
print(name[-4:]) # This line prints the characters from index -4 to the end
# of the string 'name'. Since index -4 corresponds to the character 'a', the output will be "arry".
print(name[1:4]) # This line prints the characters from index 1 to index 3 of the string 'name'. Since index 1 corresponds to the character 'a' and index 4 corresponds to the character 'y', the output will be "arr".
print(name[-4: -1]) # This line prints the characters from index -4 to index -2 of the string 'name'. Since index -4 corresponds to the character 'a' and index -1 corresponds to the character 'y', the output will be "arr".


print(name[:4]) # This line prints the characters from the beginning of the string 'name' to index 3. Since index 4 corresponds to the character 'y', the output will be "Harr".
print(name[1:]) # This line prints the characters from index 1 to the end of the string 'name'. Since index 1 corresponds to the character 'a', the output will be "arry".
print(name[1:5]) # This line prints the characters from index 1 to index 4 of the string 'name'. Since index 1 corresponds to the character 'a' and index 4 corresponds to the character 'y', the output will be "arry".